export const toItems = (sonolus, localize, toItem, items) => items.map((item) => toItem(sonolus, localize, item));
export const getItem = (items, nameOrItem, parent, path) => {
    if (typeof nameOrItem !== 'string')
        return nameOrItem;
    const item = items.find(({ name }) => name === nameOrItem);
    if (!item)
        throw new Error(`${parent}: ${nameOrItem} not found (${path})`);
    return item;
};
